import { useState } from "react";
import LoginForm from "./components/LoginForm";
import Welcome from "./components/Welcome";

function App() {
  const [isAuthed, setIsAuthed] = useState(false);
  const [errorMessage, setErrorMessage] = useState("");
  const [username, setUsername] = useState("");

  const handleLogin = async (creds: { username: string; password: string }) => {
    try {
      setErrorMessage("");
      const res = await fetch("/auth", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(creds),
      });
      if (res.status === 200) {
        setIsAuthed(true);
        setUsername(creds.username);
      } else {
        if (res.status === 401) {
          const data = (await res.json()) as { message: string };
          setErrorMessage(data.message);
        } else {
          throw Error(`error during auth, status code: ${res.status}`);
        }
      }
    } catch (e) {
      console.error(e);
    }
  };

  return (
    <div className="lg:container lg mx-auto m-10">
      <div>Simple react application</div>
      {isAuthed ? (
        <Welcome
          username={username}
          onLogout={() => {
            setIsAuthed(false);
            setUsername("");
          }}
        />
      ) : (
        <LoginForm
          onLogin={(creds) => void handleLogin(creds)}
          errorMessage={errorMessage}
        />
      )}
    </div>
  );
}

export default App;
